resource "aws_wafv2_web_acl_logging_configuration" "${name}_logging" {
  resource_arn            = aws_wafv2_web_acl.${name}.arn
  log_destination_configs = [aws_cloudwatch_log_group.waf.arn]
}

resource "aws_wafv2_web_acl_association" "${name}_waf" {
  resource_arn = aws_api_gateway_stage.${name}.arn
  web_acl_arn  = aws_wafv2_web_acl.api.arn
}

resource "aws_route53_query_log" "${name}_qlog" {
  zone_id                  = aws_route53_zone.${name}.zone_id
  cloudwatch_log_group_arn = aws_cloudwatch_log_group.dns.arn
}

resource "aws_backup_vault_lock_configuration" "${name}_lock" {
  backup_vault_name   = aws_backup_vault.${name}.name
  min_retention_days  = 7
  changeable_for_days = 3
}

resource "aws_route53_key_signing_key" "${name}_ksk" {
  hosted_zone_id             = aws_route53_zone.${name}.id
  key_management_service_arn = aws_kms_key.dnssec.arn
  name                       = "${name}-ksk"
}
resource "aws_route53_hosted_zone_dnssec" "${name}_dnssec" {
  hosted_zone_id = aws_route53_key_signing_key.${name}_ksk.hosted_zone_id
}
